export default {
	data() {
		return {
			imgList: [],
			modalName: null,
			latitude: 36.645008,
			longitude: 116.915131,
			covers: [{
				/* callout: {
					content: '点击图标跳转到导航',
					display: 'ALWAYS',
					color:'#FF4500'
				}, */
				width: 50,
				height: 50,
				id: '_marker_1',
				latitude: 36.645008,
				longitude: 116.915131,




				iconPath: '../../static/location.png',


				iconPath: '../../../static/locationfill.png',

			}],
		}
	},
	methods: {
		showModal(e) {
			console.log('看看');
			console.log(e);
			this.modalName = e.currentTarget.dataset.target
		},
		hideModal(e) {
			this.modalName = null
		},
		ChooseImage() {
			uni.chooseImage({
				count: 4, //默认9
				sizeType: ['original', 'compressed'], //可以指定是原图还是压缩图，默认二者都有
				sourceType: ['album'], //从相册选择
				success: (res) => {
					if (this.imgList.length != 0) {
						this.imgList = this.imgList.concat(res.tempFilePaths)
					} else {
						this.imgList = res.tempFilePaths
					}
				}
			});
		},
		ViewImage(e) {
			console.log(e)
			uni.previewImage({
				urls: this.imgList,
				current: e.currentTarget.dataset.url
			});
		},
		DelImg(e) {
			uni.showModal({
				title: '删除确认',
				content: '确定要删除这张图片？',
				cancelText: '再想想',
				confirmText: '确定',
				success: res => {
					if (res.confirm) {
						this.imgList.splice(e.currentTarget.dataset.index, 1)
					}
				}
			})
		},
	}
}
